import{_ as o,c as n,o as r,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const g=JSON.parse(`{"title":"v1.1.31: Sub-Agents Don't Count Quota, New Retro Theme","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.31.md","filePath":"en/changelog/v1.1.31.md","lastUpdated":1772014034000}`),i={name:"en/changelog/v1.1.31.md"};function s(l,a,h,d,u,c){return r(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-31-sub-agents-don-t-count-quota-new-retro-theme" tabindex="-1">v1.1.31: Sub-Agents Don&#39;t Count Quota, New Retro Theme <a class="header-anchor" href="#v1-1-31-sub-agents-don-t-count-quota-new-retro-theme" aria-label="Permalink to “v1.1.31: Sub-Agents Don&#39;t Count Quota, New Retro Theme”">​</a></h1><p><strong>Release Date</strong>: January 22, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update brings real benefits: sub-agent invocations no longer count toward your quota limits! Plus, it adds the retro-style Gruvbox theme and Traditional Chinese support.</p><hr><h2 id="major-benefit-sub-agents-exempt-from-quota" tabindex="-1">Major Benefit: Sub-Agents Exempt from Quota <a class="header-anchor" href="#major-benefit-sub-agents-exempt-from-quota" aria-label="Permalink to “Major Benefit: Sub-Agents Exempt from Quota”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Now, <strong>sub-agent sessions</strong> initiated by the main Agent will be marked as <code>agent-initiated</code> and no longer count toward your API usage quota limits.</p><h3 id="what-does-this-mean" tabindex="-1">What does this mean? <a class="header-anchor" href="#what-does-this-mean" aria-label="Permalink to “What does this mean?”">​</a></h3><p>Previously, you might have worried that calling several helpers (sub-agents) would consume too much quota. Now:</p><ul><li>You can confidently let AI launch a <code>search</code> agent to look up information.</li><li>Or launch a <code>code-review</code> agent to review code.</li><li>These subtask consumptions will be more &quot;lenient&quot; (depending on your quota policy, but typically means they don&#39;t count toward main quota or have separate allocation).</li></ul><h3 id="how-to-benefit" tabindex="-1">How to benefit? <a class="header-anchor" href="#how-to-benefit" aria-label="Permalink to “How to benefit?”">​</a></h3><p>No action required. Simply upgrade to v1.1.31 to activate.</p><hr><h2 id="new-look-gruvbox-theme" tabindex="-1">New Look: Gruvbox Theme <a class="header-anchor" href="#new-look-gruvbox-theme" aria-label="Permalink to “New Look: Gruvbox Theme”">​</a></h2><h3 id="what-is-gruvbox" tabindex="-1">What is Gruvbox? <a class="header-anchor" href="#what-is-gruvbox" aria-label="Permalink to “What is Gruvbox?”">​</a></h3><p>Gruvbox is a classic retro-style color scheme with warm tones and moderate contrast, easy on the eyes for long coding sessions.</p><h3 id="how-to-switch" tabindex="-1">How to switch? <a class="header-anchor" href="#how-to-switch" aria-label="Permalink to “How to switch?”">​</a></h3><p>In OpenCode Desktop or Web version settings:</p><ol><li>Open <strong>Settings</strong></li><li>Find <strong>Theme</strong></li><li>Select <strong>Gruvbox</strong></li></ol><hr><h2 id="language-support-traditional-chinese" tabindex="-1">Language Support: Traditional Chinese <a class="header-anchor" href="#language-support-traditional-chinese" aria-label="Permalink to “Language Support: Traditional Chinese”">​</a></h2><h3 id="new-support" tabindex="-1">New Support <a class="header-anchor" href="#new-support" aria-label="Permalink to “New Support”">​</a></h3><p>OpenCode now supports <strong>Traditional Chinese</strong> interface! The original &quot;Chinese&quot; option has been renamed to &quot;Chinese (Simplified)&quot; for clarity.</p><h3 id="how-to-set" tabindex="-1">How to set? <a class="header-anchor" href="#how-to-set" aria-label="Permalink to “How to set?”">​</a></h3><ol><li>Open <strong>Settings</strong></li><li>Find <strong>Language</strong></li><li>Select <strong>Traditional Chinese</strong></li></ol><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Frequently use Task/Subagent features</td><td>✅ <strong>Must upgrade</strong> (saves quota!)</td></tr><tr><td>Like retro color schemes</td><td>✅ Recommended upgrade</td></tr><tr><td>Prefer Traditional Chinese interface</td><td>✅ Recommended upgrade</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',31),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Mark subagent sessions as agent-initiated to exclude them from quota limits</li><li>Add chat.headers hook and update codex and copilot plugins to use it (thanks to @ananas-viber for catching)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add Gruvbox theme to Web and App (@swolg)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Add Traditional Chinese language support and rename Chinese to Chinese (Simplified) (@alexyaroshuk)</li><li>Add Russian language support (@alexyaroshuk)</li><li>Polish translations in app (@neriousy)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const m=o(i,[["render",s]]);export{g as __pageData,m as default};
